 direction\ndecloakCode = nil\n\nlocal function clearDecloakProxies()\n    if assignedShip ~= nil then\n        Global.call(\u0022DeleteShipProxies\u0022, { ship_guid = assignedShip.getGUID() })\n    end\nend\n\nlocal function startDecloakProxySelection(move_code_prefix)\n    if assignedShip == nil then\n        return false\n    end\n\n    __XW_TokenIdle = false\n    clearDecloakProxies()\n    self.clearButtons()\n    self.createButton({\n        [\u0027function_owner\u0027] = self,\n        [\u0027click_function\u0027] = \u0027selfDestruct\u0027,\n        [\u0027label\u0027] = \u0027Delete\u0027,\n        [\u0027position\u0027] = { 0, 0.25, 2 },\n        [\u0027rotation\u0027] = { 0, 0, 0 },\n        [\u0027width\u0027] = 750,\n        [\u0027height\u0027] = 500,\n        [\u0027font_size\u0027] = 250\n    })\n    self.createButton({\n        [\u0027function_owner\u0027] = self,\n        [\u0027click_function\u0027] = \u0027spawnDecloakButtons\u0027,\n        [\u0027label\u0027] = \u0027Back\u0027,\n        [\u0027position\u0027] = { 0, 0.25, 1 },\n        [\u0027rotation\u0027] = { 0, 0, 0 },\n        [\u0027width\u0027] = 750,\n        [\u0027height\u0027] = 500,\n        [\u0027font_size\u0027] = 250\n    })\n\n    local _, success = Global.call(\u0022SpawnProxyOptions\u0022, {\n        ship_guid = assignedShip.getGUID(),\n        move_codes = {\n            front = move_code_prefix .. \u00271\u0027,\n            center = move_code_prefix .. \u00272\u0027,\n            back = move_code_prefix .. \u00273\u0027,\n        },\n        callback_guid = self.getGUID(),\n        callback_function = \u0022spawnFinalButtons\u0022,\n    })\n\n    if not success then\n        spawnDecloakButtons()\n        return false\n    end\n\n    return true\nend\n\n-- Save self state\nfunction onSave()\n    if assignedShip ~= nil then\r\n        local state = { assignedShipGUID = assignedShip.getGUID() }\r\n        return JSON.encode(state)\r\n    end\r\nend\r\n\r\n-- Restore self state\r\nfunction onLoad(save_state)\r\n    if save_state ~= \u0027\u0027 and save_state ~= \u0027null\u0027 and save_state ~= nil then\r\n        local assignedShipGUID = JSON.decode(save_state).assignedShipGUID\r\n        if assignedShipGUID ~= nil and getObjectFromGUID(assignedShipGUID) ~= nil then\r\n            assignedShip = getObjectFromGUID(assignedShipGUID)\r\n            spawnFirstButtons()\r\n        end\r\n    end\r\nend\r\n\r\n-- Spawn initial decloak/delete buttons\r\nfunction spawnFirstButtons()\n    __XW_TokenIdle = true\n    clearDecloakProxies()\n    self.clearButtons()\n    self.createButton({\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027spawnDecloakButtons\u0027,\r\n        [\u0027label\u0027] = \u0027Decloak\u0027,\r\n        [\u0027position\u0027] = { 0, 0.25, -1.5 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 1000,\r\n        [\u0027height\u0027] = 500,\r\n        [\u0027font_size\u0027] = 250\r\n    })\r\n    self.createButton({\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027selfDestruct\u0027,\r\n        [\u0027label\u0027] = \u0027Delete\u0027,\r\n        [\u0027position\u0027] = { 0, 0.25, 1.5 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 1000,\r\n        [\u0027height\u0027] = 500,\r\n        [\u0027font_size\u0027] = 250\r\n    })\r\nend\r\n\r\n-- Assign on drop near a small base ship\r\nfunction onDropped()\r\n    if assignedShip == nil then\r\n        local nearest = Global.call(\u0022API_FindNearestShip\u0022, { object = self, max_distance = 80 })\r\n        if nearest ~= nil then\r\n            printToAll(\u0027Cloak token assigned to \u0027 .. nearest.getName(), { 0.2, 0.2, 1 })\r\n            self.setRotation(nearest.getRotation())\r\n            spawnFirstButtons()\r\n            assignedShip = nearest\r\n        end\r\n    end\r\nend\r\n\r\n-- Spawn undo/delete/slide buttons (after a move)\r\nfunction spawnFinalButtons()\n    undoToBackCount = 1\n    clearDecloakProxies()\n    self.clearButtons()\n    self.createButton({\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027performUndo\u0027,\r\n        [\u0027label\u0027] = \u0027Undo\u0027,\r\n        [\u0027position\u0027] = { 0, 0.25, -1.5 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 1000,\r\n        [\u0027height\u0027] = 500,\r\n        [\u0027font_size\u0027] = 250\r\n    })\r\n    self.createButton({\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027selfDestruct\u0027,\r\n        [\u0027label\u0027] = \u0027Delete\u0027,\r\n        [\u0027position\u0027] = { 0, 0.25, 1.5 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 1000,\r\n        [\u0027height\u0027] = 500,\r\n        [\u0027font_size\u0027] = 250\r\n    })\r\nend\r\n\r\nfunction spawnDecloakAllignmentSet()\r\n    __XW_TokenIdle = false\r\n    self.clearButtons()\r\n    self.createButton({\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027decloakForwardAligned\u0027,\r\n        [\u0027label\u0027] = \u0027Forward\u0027,\r\n        [\u0027position\u0027] = { 0, 0.25, -1.1 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 1200,\r\n        [\u0027height\u0027] = 520,\r\n        [\u0027font_size\u0027] = 250\r\n    })\r\n    self.createButton({\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027decloakMiddleAligned\u0027,\r\n        [\u0027label\u0027] = \u0027Middle\u0027,\r\n        [\u0027position\u0027] = { 0, 0.25, 0 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 1200,\r\n        [\u0027height\u0027] = 520,\r\n        [\u0027font_size\u0027] = 250\r\n    })\r\n    self.createButton