[\u0027click_function\u0027] = \u0027decloakRF\u0027,\r\n        [\u0027label\u0027] = \u0027RF\u0027,\r\n        [\u0027position\u0027] = { 1.5, 0.25, -1.1 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 365,\r\n        [\u0027height\u0027] = 520,\r\n        [\u0027font_size\u0027] = 250\r\n    })\r\n    self.createButton({\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027decloakRB\u0027,\r\n        [\u0027label\u0027] = \u0027RB\u0027,\r\n        [\u0027position\u0027] = { 1.5, 0.25, 1.1 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 365,\r\n        [\u0027height\u0027] = 520,\r\n        [\u0027font_size\u0027] = 250\r\n    })\r\nend\r\n\r\n\r\n-- Spawn back/delete/moves buttons (regular or Echo)\r\nfunction spawnDecloakButtons()\n    __XW_TokenIdle = false\n    clearDecloakProxies()\n    self.clearButtons()\n    if assignedShip.getTable(\u0027Data\u0027).xws ~= \u0022echo\u0022 then\r\n        spawnNormalDecloakOptions()\r\n    end\r\n    if assignedShip.getName():find(\u0027Echo\u0027) ~= nil then\r\n        spawnEchoDecloakOptions()\r\n    end\r\n    self.createButton({\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027selfDestruct\u0027,\r\n        [\u0027label\u0027] = \u0027Delete\u0027,\r\n        [\u0027position\u0027] = { 0, 0.25, 2 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 750,\r\n        [\u0027height\u0027] = 500,\r\n        [\u0027font_size\u0027] = 250\r\n    })\r\n    self.createButton({\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027resetToFirst\u0027,\r\n        [\u0027label\u0027] = \u0027Back\u0027,\r\n        [\u0027position\u0027] = { 0, 0.25, 1 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 750,\r\n        [\u0027height\u0027] = 500,\r\n        [\u0027font_size\u0027] = 250\r\n    })\r\nend\r\n\r\n\r\nfunction decloakL()\n    startDecloakProxySelection(\u0022cl\u0022)\nend\n\nfunction decloakR()\n    startDecloakProxySelection(\u0022cr\u0022)\nend\n\nfunction decloakLF()\n    startDecloakProxySelection(\u0022elf\u0022)\nend\n\nfunction decloakLB()\n    startDecloakProxySelection(\u0022elb\u0022)\nend\n\nfunction decloakRF()\n    startDecloakProxySelection(\u0022erf\u0022)\nend\n\nfunction decloakRB()\n    startDecloakProxySelection(\u0022erb\u0022)\nend\n\r\n\r\n--------\r\n-- DECLOAK MOVES\r\nfunction decloakF()\r\n    if Global.call(\u0027API_PerformMove\u0027, { code = \u0027cs\u0027, ship = assignedShip }) then\r\n        spawnFinalButtons()\r\n    end\r\nend\r\n\r\nfunction decloakFR()\r\n    if Global.call(\u0027API_PerformMove\u0027, { code = \u0027esr\u0027, ship = assignedShip }) then\r\n        spawnFinalButtons()\r\n    end\r\nend\r\n\r\nfunction decloakFL()\r\n    if Global.call(\u0027API_PerformMove\u0027, { code = \u0027ese\u0027, ship = assignedShip }) then\r\n        spawnFinalButtons()\r\n    end\r\nend\r\n\r\nfunction decloakForwardAligned()\r\n    if Global.call(\u0027API_PerformMove\u0027, { code = decloakCode .. \u00271\u0027, ship = assignedShip }) then\r\n        spawnFinalButtons()\r\n    end\r\nend\r\n\r\nfunction decloakMiddleAligned()\r\n    if Global.call(\u0027API_PerformMove\u0027, { code = decloakCode .. \u00272\u0027, ship = assignedShip }) then\r\n        spawnFinalButtons()\r\n    end\r\nend\r\n\r\nfunction decloakBackAligned()\r\n    if Global.call(\u0027API_PerformMove\u0027, { code = decloakCode .. \u00273\u0027, ship = assignedShip }) then\r\n        spawnFinalButtons()\r\n    end\r\nend\r\n\r\n-- END DECLOAK MOVES\r\n--------\r\n\r\n-- Destroy self\r\nfunction selfDestruct()\n    clearDecloakProxies()\n    self.destruct()\nend\n\n-- Back to first buttons\nfunction resetToFirst()\n    clearDecloakProxies()\n    spawnFirstButtons()\nend\n\r\n-- Undo move, if undid all back to decloak buttons\r\nfunction performUndo()\r\n    assignedShip.setDescription(\u0027q\u0027)\r\n    undoToBackCount = undoToBackCount - 1\r\n    if undoToBackCount \u003C= 0 then\r\n        spawnDecloakButtons()\r\n    end\r\nend\r\n\nend)\n__bundle_register(\u0022Dim\u0022, function(require, _LOADED, __bundle_register, __bundle_modules)\n-- ~~~~~~\r\n-- Script by dzikakulka\r\n-- Issues, history at: http://github.com/tjakubo2/TTS_xwing\r\n--\r\n-- X-Wing related measurements for TTS\r\n-- ~~~~~~\r\n\r\nlocal Dim = {}\r\n\r\n-- adjusted length = 40mm = 1.4536igu\r\n-- 1mm = 0.03612igu\r\nDim.mm_igu_ratio = 0.03637\r\n\r\n-- 40mm = 1.445igu\r\n-- (s1 length / small base size)\r\n\r\n-- 1mm = 0.036125igu\r\n-- mm_igu_ratio = 0.036125\r\n\r\n-- Millimeter dimensions of ship bases\r\nDim.mm_baseSize = {\r\n    small = 40,\r\n    medium = 60,\r\n    large = 80,\r\n    huge = 80,\r\n    smallBase = 40,\r\n    mediumBase = 60,\r\n    largeBase = 80,\r\n    hugeBase = 80,\r\n    objective = 36,\r\n}\r\n\r\nDim.mm_smallBase = Dim.mm_baseSize.small\r\nDim.mm_mediumBase = Dim.mm_baseSize.medium\r\nDim.mm_largeBase = Dim.mm_baseSize.large\r\n\r\n----------------------------------------\r\n-- Standard X-Wing Maneuver Templates --\r\n----------------------------------------\r\n\r\nDim.XWingTemplates = {\r\n    straight = { 40, 80, 120, 160, 200 }, -- Speed to millimeters\r\n    turn = { 35, 62.5, 90 },              -- Turn Middle Radius (mm)\r\n    bank = { 80, 130, 180 },              -- Bank Middle Radius (mm)\r\n}\r\n\r\n-- Millimeter dimensions for cards\r\nDim.mm_upgrade_width = 41\r\nDim.mm_upgrade_height = 63\r\nDim.mm_pilot_width = 63.5\r\nDim.mm_pilot_height = 88\r\n\r\nDim.mm_ship_scale = vector(0.629, 0.629, 0.629)\r\n\r\nDim.mm_cardSize = {\r\n    upgrade = { width = 41, height = 63 },\r\n    pilot = { width = 63.5, height = 88 }\r\n}\r\n\r\n-- Millimeter dimension for dial cards\r\nDim.mm_dialSize = 54\r\n\r\n-- Convert argument from MILLIMETERS to IN-GAME UNITS\r\nfunction Dim.Convert_mm_igu(millimeters)\r\n    return millimeters * Dim.mm_igu_ratio\r\nend\r\n\r\n-- Convert argument from IN-GAME UNITS to MILLIMETERS\r\nfunction Dim.Convert_igu_mm(in_game_units)\r\n    return in_game_units / Dim.mm_igu_ratio\r\nend\r\n\r\nreturn Dim\r\n\nend)\nreturn __bundle_require(\u0022Cloak.efc148.lua\u0022)